const entries = $('CreateTransactionEntry').all();

let rates = null;
try {
  const ratePayload = $('GetConversionRates').first()?.json;
  rates = ratePayload?.sgd ?? null;
} catch (e) {
  rates = null;
}

for (const item of entries) {
  const currency = String(item.json.currency || '').toUpperCase();
  const amount = Number(item.json.amount);

  // Safe fallback: if FX rate is unavailable/invalid, keep original amount
  item.json.amount_base_currency = amount;

  if (currency !== 'SGD' && Number.isFinite(amount)) {
    const rate = Number(rates?.[currency.toLowerCase()]);
    if (Number.isFinite(rate) && rate > 0) {
      item.json.amount_base_currency = Math.round((amount / rate) * 100) / 100;
      item.json.fx_fallback_used = false;
    } else {
      item.json.fx_fallback_used = true;
    }
  } else {
    item.json.fx_fallback_used = false;
  }

  const raw = [
    item.json.bank,
    item.json.identifier,
    item.json.merchant,
    item.json.amount,
    item.json.time
  ].join('|');

  item.json.transaction_hash = raw;
}

return entries;

