let result = []
for (const item of $input.all()) {
  var html = item.json.textHtml

  if (item.json.textHtml.includes("maribank")) {
    extractMaribank(html)
  }

}


function extractMaribank(html) {
  // Optional: strip excessive whitespace to make regex easier
  const cleaned = html.replace(/\s+/g, " ");

  // 1️⃣ Extract Merchant
  const merchantMatch = cleaned.match(
    /payment to\s+(.+?)\s+on your credit card ending/i
  );
  const merchant = merchantMatch ? merchantMatch[1].trim() : null;

  // 2️⃣ Extract Card Ending
  const cardMatch = cleaned.match(/credit card ending\s+(\d{4})/i);
  const cardEnding = cardMatch ? cardMatch[1] : null;

  // 3️⃣ Extract Amount
  const amountMatch = cleaned.match(/([A-Z]{3})\s*([\d,]+\.\d{2})/);

  let currency = null;
  let amount = null;

  if (amountMatch) {
    currency = amountMatch[1];
    amount = parseFloat(amountMatch[2].replace(/,/g, ""));
  }

  const dateMatch = cleaned.match(
  /(\d{1,2}\s\w+\s\d{4}\s\d{2}:\d{2})\s*SGT/i
);

  let transactionRaw = null;
  let transactionISO = null;

  if (dateMatch) {
    transactionRaw = dateMatch[1];

    // Convert to ISO format for DB
    const parsedDate = new Date(transactionRaw + " GMT+0800");
    transactionISO = parsedDate.toISOString();
  }


  result.push( {
    bank: "MariBank",
    merchant,
    currency,
    amount,
    time: transactionISO,
    identifier: cardEnding,
    normalize_merchant: normalizeMerchant(merchant)
  })
}

function normalizeMerchant(name) {
  return name
    .toUpperCase()
    .replace(/[^A-Z0-9]/g, "")
    .trim();
}

return result

