function extractUOB(text) {
  const amountMatch = text.match(/([A-Z]{3})\s([\d,]+\.\d{2})/);
  const currency = amountMatch ? amountMatch[1] : null;
  const amount = amountMatch ? parseFloat(amountMatch[2].replace(/,/g, "")) : null;

  const cardMatch = text.match(/Card ending\s(\d{4})/i);
  const cardEnding = cardMatch ? cardMatch[1] : null;

  const merchantMatch = text.match(/at\s(.+?)\./i);
  const merchant = merchantMatch ? merchantMatch[1].trim() : null;

  const dateMatch = text.match(/on\s(\d{2}\/\d{2}\/\d{2})/i);
  let transactionISO = null;

  if (dateMatch) {
    const parts = dateMatch[1].split('/');
    const year = "20" + parts[2];
    const month = parts[1];
    const day = parts[0];
    transactionISO = new Date(`${year}-${month}-${day}T12:00:00+08:00`).toISOString();
  }

  result.push({
    bank: "UOB",
    merchant,
    currency,
    amount,
    time: transactionISO,
    identifier: cardEnding,
    normalize_merchant: normalizeMerchant(merchant || "")
  });
}

function normalizeMerchant(name) {
  return name.toUpperCase().replace(/[^A-Z0-9]/g, "").trim();
}

return result;

